// Get all incoming items
const items = $input.all();

// Extract the text field from each item
const texts = items.map(item => item.json.idea);

// Concatenate them (adjust the separator as needed)
const concatenated = texts.join(", ");

// Return a single item with the concatenated text
return [{ json: { mergedText: concatenated } }];

// Add a new field called 'myNewField' to the JSON of the item
$input.item.json.myNewField = 1;

let url = $input.item.json.data.text

if (typeof url === 'string') {
  const match = url.match(/\/d\/([^/]+)/);
  if (match) {
    url =
      `https://drive.usercontent.google.com/download?id=${match[1]}`;
  }
}

return {url: url};

const items = $input.all();

const ideasString = items
  .map((item, i) => `Idea ${i + 1}: ${item.json.Idea}`)
  .join(", ");

return [
  {
    json: {
      ideas: ideasString
    }
  }
];
